import React from "react";
import { Container, Tails, Body, Spacer } from "./styles";

const Banner: React.FC = () => {
  return (
    <>
      <Container>
        <Tails left />
        <Spacer>Bespoke Audio Services</Spacer>
        <Body>Bespoke Audio Services</Body>
        <Tails right />
      </Container>
    </>
  );
};

export default Banner;
